import{_ as t,o as e,c as r,ae as o}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Reporting and Analytics","description":"","frontmatter":{"title":"Reporting and Analytics","slug":"cost-data-reporting-analytics"},"headers":[],"relativePath":"marketer-hub/cost-data-reporting-analytics.md","filePath":"marketer-hub/cost-data-reporting-analytics.md"}'),n={name:"marketer-hub/cost-data-reporting-analytics.md"};function i(s,a,l,c,d,h){return e(),r("div",null,[...a[0]||(a[0]=[o('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The Branch Dashboard will be your primary hub for viewing cost data across all of your integrated ad partners.</p><p>You will be able to make better ad-optimized decisions more quickly, without having to navigate to each partner dashboard to measure cost.</p><h2 id="handling-currencies" tabindex="-1">Handling Currencies <a class="header-anchor" href="#handling-currencies" aria-label="Permalink to &quot;Handling Currencies&quot;">​</a></h2><p>Branch applies the <a href="https://openexchangerates.org/" target="_blank" rel="noreferrer">current exchange rate</a> every 30 minutes for today&#39;s spend and then daily for days after that to convert it to USD and then converted to your local currency (<a href="./advanced-settings-configuration.html#local-currency">if you set it</a>). If it is the same currency, then Branch won&#39;t apply any exchange rates to your local currency.</p><h2 id="activity" tabindex="-1">Activity <a class="header-anchor" href="#activity" aria-label="Permalink to &quot;Activity&quot;">​</a></h2><p>Once cost data is flowing through Branch from the ad network(s), you can view cost through <a href="./paid-ads-analytics.html">Ads Analytics</a>.</p><p>Navigate to the <strong>Activity</strong> <a href="https://branch.dashboard.branch.io/ads/analytics/activity" target="_blank" rel="noreferrer">tab</a> on the <strong>Analytics</strong> <a href="https://branch.dashboard.branch.io/ads/analytics/" target="_blank" rel="noreferrer">page</a>, which is in the <strong>Ads</strong> section of the Branch Dashboard.</p><p><em>[Image: 0ca5af3-Cost_Analytics.png]</em>.png)</p><h2 id="unpopulated-values" tabindex="-1">Unpopulated Values <a class="header-anchor" href="#unpopulated-values" aria-label="Permalink to &quot;Unpopulated Values&quot;">​</a></h2><p>You may see specific columns/dimensions displayed as <strong>Unpopulated</strong> in your Dashboard reports. This is due to limitations from the ad partner and what dimensions they can send for the Cost Data. This varies by ad partner and dimension.</p><p>For example, if we are reporting on cost and comparing by country, the following information will be displayed:</p><p>In this case, when drilling down to the country level, the cost cannot be broken down, so Branch displays country on a different row.</p><h2 id="cost-availability" tabindex="-1">Cost Availability <a class="header-anchor" href="#cost-availability" aria-label="Permalink to &quot;Cost Availability&quot;">​</a></h2><p>When looking at Dashboard Reports and Exports, Branch applies certain rules/formats that determine availability for cost:</p><table tabindex="0"><thead><tr><th>Availability</th><th>Description</th></tr></thead><tbody><tr><td>Cost Rule</td><td>This is a rule that is applied across all of Branch for a combination of Partners and Campaign IDs that if there are no Branch tracked clicks, installs, reinstalls, opens, web session start, or SKAdNetwork downloads then Cost isn&#39;t shown.</td></tr><tr><td>Always Enabled</td><td>The following partners/sources always show cost data, regardless of attribution matching: - <a href="./criteo.html">Criteo</a> - <a href="./google-marketing-platform.html">GMP</a> (CM360 Country Mapping, CM360 Device Mapping, and DV360) - <a href="./cost-data-via-email-import.html">ROI Hub email ingestion</a> - <a href="./cost-data-via-file-upload.html">ROI Hub file ingestion</a></td></tr><tr><td>Cost Reporting</td><td>To analyze Cost you can use the following pages in the Branch Dashboard: Summary, Unified Analytics, Ads Analytics, and Cohorts. Or the following APIs: Query API and Cohort Exports API.</td></tr></tbody></table>',16)])])}const y=t(n,[["render",i]]);export{u as __pageData,y as default};
